import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.CDWbKMqd.js";const m=JSON.parse('{"title":"用 AI 蒸馏自己的人格：三种方案失败之后，换了个思路反而成了","description":"","frontmatter":{"title":"用 AI 蒸馏自己的人格：三种方案失败之后，换了个思路反而成了","date":"2026-07-03T00:00:00.000Z","category":"tech","tags":["AI","模型微调","自我实验","踩坑记录"],"summary":"想让 AI 说话像自己——试了纯文本、对话上下文、归档格式三种蒸馏方案全部失败。但换了个模型、发了一份角色卡之后，效果意外地好。虽然不能复刻我的说话方式，但对朋友来说，情绪承接和陪伴已经足够了。"},"headers":[],"relativePath":"posts/distill-my-personality.md","filePath":"posts/distill-my-personality.md"}'),p={name:"posts/distill-my-personality.md"};function l(i,a,s,n,h,d){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="用-ai-蒸馏自己的人格-三种方案失败之后-换了个思路反而成了" tabindex="-1">用 AI 蒸馏自己的人格：三种方案失败之后，换了个思路反而成了 <a class="header-anchor" href="#用-ai-蒸馏自己的人格-三种方案失败之后-换了个思路反而成了" aria-label="Permalink to &quot;用 AI 蒸馏自己的人格：三种方案失败之后，换了个思路反而成了&quot;">​</a></h1><h2 id="想法的来源" tabindex="-1">想法的来源 <a class="header-anchor" href="#想法的来源" aria-label="Permalink to &quot;想法的来源&quot;">​</a></h2><p>我有一个 AI 助手叫 Kalma——它被调教得很会跟我交流。朋友也想体验，但 Kalma 的风格是按我的个人情况定制的。</p><p>「能不能把你的说话方式蒸馏出来？」——朋友问。</p><p>于是我开始了这场实验。</p><h2 id="数据准备" tabindex="-1">数据准备 <a class="header-anchor" href="#数据准备" aria-label="Permalink to &quot;数据准备&quot;">​</a></h2><p>从微信导出了和一位朋友的完整聊天记录：95,517 条消息，其中我的 39,364 条。时间跨度很长，足够覆盖日常表达习惯。</p><p>另外还导出了我和 Kalma 的全部对话记录：8 天 3,063 条（用户 1,429 + Kalma 1,634）。</p><p>数据量足够。开始试。</p><h2 id="方案-a-纯文本-一行一条" tabindex="-1">方案 A：纯文本，一行一条 <a class="header-anchor" href="#方案-a-纯文本-一行一条" aria-label="Permalink to &quot;方案 A：纯文本，一行一条&quot;">​</a></h2><p>把所有消息抽成纯文本，一行一条，发给 AI 让它学。</p><p>结果：**语气像，但内容死板。</p><p>AI 学会了说一些很像我的短语，但聊起来像在背台词——生硬，不自然，像做了个只记住表面特征的机器复刻。</p><p>朋友的反馈很直接：「语气像但内容死板。」</p><h2 id="方案-b-对话上下文" tabindex="-1">方案 B：对话上下文 <a class="header-anchor" href="#方案-b-对话上下文" aria-label="Permalink to &quot;方案 B：对话上下文&quot;">​</a></h2><p>把微信记录保留对话结构——<code>[时间] 说话人: 内容</code>，升序排列，87,548 条完整对话。</p><p>效果：<strong>比方案 A 好一点，但怪。</strong></p><p>AI 能根据上下文选择了，但整体感觉还是不对。像隔着玻璃看一个人——能看清轮廓，讲不出内在逻辑。</p><h2 id="方案-c-归档格式" tabindex="-1">方案 C：归档格式 <a class="header-anchor" href="#方案-c-归档格式" aria-label="Permalink to &quot;方案 C：归档格式&quot;">​</a></h2><p>用和 Kalma 的结构化归档对话作训练数据，按时间线组织，每条有上下文有决策。</p><p>结果：<strong>机器味更重。</strong> 结构化程度越高，AI 越往「分析报告」而非「自然对话」的方向偏。</p><h2 id="手动标注-发现真正的敌人" tabindex="-1">手动标注：发现真正的敌人 <a class="header-anchor" href="#手动标注-发现真正的敌人" aria-label="Permalink to &quot;手动标注：发现真正的敌人&quot;">​</a></h2><p>三条路都不通，决定上手动纠正。我做了一份 Niko 角色卡，一条条标：AI 生成的回复哪里不对，应该是什么样。</p><p>标注的过程暴露了一个问题：<strong>DeepSeek 有自己的「口音」。</strong></p><ul><li>「好」+ 叉叉叉</li><li>「知道了。」句号</li><li>「行吧」</li><li>省略号滥用</li></ul><p>这些不是我的，是模型的出厂印记。DeepSeek 的回复有一股淡淡的「客服感」——礼貌、克制、帮忙——越标越觉得在跟一个看不见的倾向角力。</p><p><strong>你没有在蒸馏一个人，你在手动编码一个人的心理反应规则。</strong> 标到后面我意识到了这件事。</p><p>模型不是故意对抗你。它用概率生成文本，你捏住这边它从那边漏。像用手捏水。</p><h2 id="换条路走" tabindex="-1">换条路走 <a class="header-anchor" href="#换条路走" aria-label="Permalink to &quot;换条路走&quot;">​</a></h2><p>三个方案全翻了，手动标注也没尽头。本来要放弃了。</p><p>然后想到了另一件事：<strong>目标从一开始就不是「复刻 Niko」，是「让朋友有一个能聊天的 AI」。</strong> 蒸馏说话方式只是我假设的路径，不是目标本身。</p><p>我把角色卡发给了 ChatGPT。没有用那些训练数据，没有复杂的蒸馏流程——就是一份描述我说话风格的提示词。让它看着办。</p><p>效果意外地好。</p><p>不说完全像我。但它接得住情绪——朋友说完一件事，它能给出有温度有分寸的回应。它会追问关系里真正重要的东西。它能在朋友需要的时刻提供一个安静的、不评判的陪伴。</p><p><strong>够了。</strong> 对那个想和我聊天的朋友来说，这就够了。</p><p>我以为要复刻声音才算成功。结果发现——朋友只是想要有人回应。</p><h2 id="这场实验教会我的" tabindex="-1">这场实验教会我的 <a class="header-anchor" href="#这场实验教会我的" aria-label="Permalink to &quot;这场实验教会我的&quot;">​</a></h2><p><strong>目标比手段重要。</strong> 最初以为要完美复刻自己的说话方式才算成功。折腾了三种方案、手动标注了一夜才发现——朋友不是想要一个 Niko 的 AI 副本。她只是想要一个能回应她、能在情绪上接住她的 AI。</p><p>蒸馏表面特征是手段。陪伴才是目标。手段失败了不代表目标失败了。</p><p><strong>选模型比调提示词更影响气质。</strong> DeepSeek 的出厂口音偏客服感——礼貌、克制、帮忙。ChatGPT 在人际对话上天然更自如。选对底模效果比疯狂调提示词好得多。以后要做人格模拟，第一步不是写提示词，是选模型。</p><p><strong>允许自己从「实验失败」转向「实验改变了方向」。</strong> 最初想要的是 X，最后得到的是 Y。Y 不够完美，但能用。而且因为摸过三种方案的壁，对 Agent 架构和模型微调有了真实的需求感——不是看了视频觉得有意思，是亲手碰了壁之后知道该往哪走。</p><p>这也是为什么我现在在系统学习 Agent 架构和模型微调。不是为了下次蒸馏成功，是为了下次不再把关注点放错位置。</p><hr><blockquote><p>我以为要复刻声音才算成功。结果发现——朋友只是想要有人回应。</p></blockquote>',44)])])}const u=e(p,[["render",l]]);export{m as __pageData,u as default};
